const raw = $input.first().json;
const body = raw.body || raw;
const isTwilio = !!(body.From && body.Body !== undefined);
const telefono = isTwilio ? (body.From||'').replace('whatsapp:','').replace('+','') : (body.telefono||'unknown');
const msgOriginal = (isTwilio ? body.Body : body.mensaje) || '';
const mensaje = msgOriginal.toLowerCase().trim();
const staticData = $getWorkflowStaticData('global');
if (!staticData.sessions) staticData.sessions = {};

const ODONTOLOGOS = {
  '1': { id:'1', nombre:'Dr. Alejandro Contreras', especialidad:'Implantolog\u00eda y Cirug\u00eda', calendar_id:'4bc56f0d270b7a39841779f0fb8ea4ae5f81768619c1d1e080bc48b39e0b4415@group.calendar.google.com', dias:[1,2,3,4,5,6], inicio:'08:00', fin:'17:00', fin_sabado:'13:00', duracion_min:60 },
  '2': { id:'2', nombre:'Dra. Mar\u00eda B. Fuenmayor', especialidad:'Ortodoncia', calendar_id:'467b840c9c441c28dc850a65b59ff5b80041c9069b36ab52bb2845be8fa1953e@group.calendar.google.com', dias:[1,3,5], inicio:'09:00', fin:'18:00', duracion_min:60 },
  '3': { id:'3', nombre:'Dr. Germ\u00e1n Valenzuela', especialidad:'Odontolog\u00eda General', calendar_id:'ee0b43d672aa375fd063b8d6a2c74dab6f2bd2a1da36a31300aef895cf991d8c@group.calendar.google.com', dias:[2,3,4,5,6], inicio:'08:00', fin:'16:00', duracion_min:45 },
  '4': { id:'4', nombre:'Dra. Vanessa Touza', especialidad:'Odontolog\u00eda Est\u00e9tica', calendar_id:'cb7d0c4882de72e7b799c6f0c91291beef2dca67a9f23485428203f786ee3e4c@group.calendar.google.com', dias:[1,2,3,4], inicio:'10:00', fin:'19:00', duracion_min:60 },
  '5': { id:'5', nombre:'Dra. Beatriz Bravo', especialidad:'Radiolog\u00eda', calendar_id:'2a2d690e77424c331b675affdc481a35da4b2e4bb96683827553f1f28d70a1c5@group.calendar.google.com', dias:[1,2,3,4,5], inicio:'08:00', fin:'15:00', duracion_min:30 }
};

const MENU = '\ud83e\uddb7 *\u00a1Bienvenido a Implantarte!*\n\n\u00bfEn qu\u00e9 puedo ayudarte hoy?\n\n1\ufe0f\u20e3 Agendar cita de Odontolog\u00eda\n2\ufe0f\u20e3 Agendar cita de Radiolog\u00eda\n3\ufe0f\u20e3 Consulta de Precios\n4\ufe0f\u20e3 Reenv\u00edo de Resultados\n\nResponde con el n\u00famero de tu preferencia.';

let session = staticData.sessions[telefono] || { estado: 'inicio' };
if (session.updated_at) {
  const min = (Date.now() - new Date(session.updated_at).getTime()) / 60000;
  if (min > 30) session = { estado: 'inicio' };
}
if (['menu','inicio','reiniciar','hola','hi','0','reset','cancelar'].includes(mensaje)) session = { estado: 'inicio' };

let respuesta = '';
let accion = 'responder';

if (session.estado === 'inicio' || session.estado === 'menu') {
  if (['1','odontolog','especialista','dentista'].some(k => mensaje.includes(k))) {
    session.servicio = 'odontologia'; session.estado = 'solicitar_nombre';
    respuesta = '\ud83d\udc64 Para agendar tu cita de *Odontolog\u00eda*, escribe tu *nombre y apellido* completo.';
  } else if (['2','radiolog','rayos','rx'].some(k => mensaje.includes(k))) {
    session.servicio = 'radiologia'; session.odontologo = ODONTOLOGOS['5']; session.estado = 'solicitar_nombre_radio';
    respuesta = '\ud83d\udc64 Para agendar tu cita de *Radiolog\u00eda* con *Dra. Beatriz Bravo*, escribe tu *nombre y apellido* completo.';
  } else if (['3','precio','costo','tarifa'].some(k => mensaje.includes(k))) {
    session.estado = 'inicio';
    respuesta = '\ud83d\udcb0 Para consulta de *Precios* comun\u00edcate con nuestra cl\u00ednica.\n\nEscribe *hola* para volver al men\u00fa.';
  } else if (['4','result','reenv'].some(k => mensaje.includes(k))) {
    session.estado = 'inicio';
    respuesta = '\ud83d\udcc1 Para *Reenv\u00edo de Resultados* comun\u00edcate con Implantarte.\n\nEscribe *hola* para volver al men\u00fa.';
  } else { session.estado = 'inicio'; respuesta = MENU; }

} else if (session.estado === 'solicitar_nombre') {
  const nombre = msgOriginal.trim();
  if (nombre.length < 3 || /^\d+$/.test(nombre)) {
    respuesta = '\u270f\ufe0f Escribe tu *nombre y apellido* completo. Ej: _Juan P\u00e9rez_';
  } else {
    session.nombre_paciente = nombre; session.estado = 'seleccion_odontologo';
    respuesta = '\ud83d\udc4b Hola, *'+nombre+'*!\n\n*Especialistas en Odontolog\u00eda:*\n\n1\ufe0f\u20e3 Dr. Alejandro Contreras \u2014 Implantolog\u00eda y Cirug\u00eda\n2\ufe0f\u20e3 Dra. Mar\u00eda B. Fuenmayor \u2014 Ortodoncia\n3\ufe0f\u20e3 Dr. Germ\u00e1n \u2014 Odontolog\u00eda General\n4\ufe0f\u20e3 Dra. Vanessa Touza \u2014 Odontolog\u00eda Est\u00e9tica\n\nEscribe el *n\u00famero* de tu preferencia.';
  }

} else if (session.estado === 'solicitar_nombre_radio') {
  const nombre = msgOriginal.trim();
  if (nombre.length < 3 || /^\d+$/.test(nombre)) {
    respuesta = '\u270f\ufe0f Escribe tu *nombre y apellido* completo. Ej: _Juan P\u00e9rez_';
  } else {
    session.nombre_paciente = nombre; session.estado = 'verificando_disponibilidad'; session.fecha_preferida = 'proximos'; accion = 'verificar_calendar';
    respuesta = '\ud83d\udd0d Buscando horarios con *Dra. Beatriz Bravo*...';
  }

} else if (session.estado === 'seleccion_odontologo') {
  if (['1','2','3','4'].includes(msgOriginal.trim())) {
    const doc = ODONTOLOGOS[msgOriginal.trim()];
    session.odontologo = doc; session.estado = 'verificando_disponibilidad'; session.fecha_preferida = 'proximos'; accion = 'verificar_calendar';
    respuesta = '\ud83d\udd0d Buscando pr\u00f3ximos horarios con *'+doc.nombre+'*...';
  } else {
    respuesta = '\u274c Elige un n\u00famero del *1 al 4*:\n\n1\ufe0f\u20e3 Dr. Alejandro Contreras\n2\ufe0f\u20e3 Dra. Mar\u00eda B. Fuenmayor\n3\ufe0f\u20e3 Dr. Germ\u00e1n\n4\ufe0f\u20e3 Dra. Vanessa Touza';
  }

} else if (session.estado === 'fecha_hora') {
  session.fecha_preferida = msgOriginal; session.estado = 'verificando_disponibilidad'; accion = 'verificar_calendar';
  respuesta = '\ud83d\udd0d Verificando disponibilidad...';

} else if (session.estado === 'seleccion_slot') {
  const slots = session.slots_propuestos || [];
  const idx = parseInt(msgOriginal) - 1;
  if (idx >= 0 && idx < slots.length) {
    const sl = slots[idx]; session.slot_confirmado = sl; session.estado = 'confirmacion';
    const doc = session.odontologo || {};
    const fechaD = new Date(sl.inicio).toLocaleDateString('es-VE', { weekday:'long', day:'numeric', month:'long', year:'numeric' });
    respuesta = '\ud83d\udccb *Resumen de tu cita:*\n\n\ud83d\udc68\u200d\u2695\ufe0f '+(doc.nombre||'')+'\n\ud83e\uddb7 '+(doc.especialidad||'')+'\n\ud83d\udcc5 '+fechaD+'\n\ud83d\udd50 '+sl.label+' hrs\n\ud83d\udc64 '+(session.nombre_paciente||'')+'\n\n\u00bfConfirmas?\n\n*1* \u2705 S\u00ed, confirmar\n*2* \ud83d\udcc5 Elegir otro d\u00eda\n*3* \ud83d\udd04 Ver otros horarios';
  } else {
    const ls = slots.map((sl,i) => (i+1)+'\ufe0f\u20e3 '+sl.label+' hrs').join('\n');
    respuesta = '\u274c Elige *1*, *2* o *3*:\n\n'+ls;
  }

} else if (session.estado === 'confirmacion') {
  if (['1','si','s\u00ed','confirmo','ok','dale','yes'].some(k => mensaje.includes(k))) {
    session.estado = 'crear_evento'; accion = 'crear_evento'; respuesta = '\u23f3 Agendando tu cita...';
  } else if (['2','otro dia','otro d\u00eda','diferente'].some(k => mensaje.includes(k))) {
    session.estado = 'fecha_hora';
    respuesta = '\ud83d\udcc5 \u00bfPara qu\u00e9 d\u00eda prefieres?\n\nEscribe: *hoy*, *ma\u00f1ana*, el d\u00eda (ej. *lunes*) o una fecha (ej. *05/05/2026*).';
  } else if (['3','otros horarios','ver m\u00e1s'].some(k => mensaje.includes(k))) {
    session.estado = 'verificando_disponibilidad'; session.fecha_preferida = 'proximos_mas'; accion = 'verificar_calendar';
    respuesta = '\ud83d\udd0d Buscando m\u00e1s horarios...';
  } else {
    respuesta = '\u00bfConfirmas?\n\n*1* \u2705 S\u00ed\n*2* \ud83d\udcc5 Otro d\u00eda\n*3* \ud83d\udd04 Otros horarios';
  }

} else if (session.estado === 'gestion_cita') {
  const odont = session.odontologo || {};
  const slotC = session.ultima_cita || {};
  const fechaC = slotC.inicio ? new Date(slotC.inicio).toLocaleDateString('es-VE',{weekday:'long',day:'numeric',month:'long'}) : 'pr\u00f3ximamente';
  if (['1','result','realiz','asisti'].some(k => mensaje.includes(k))) {
    session.estado = 'realizacion_cita';
    respuesta = '\ud83c\udfe5 \u00bfC\u00f3mo result\u00f3 tu cita?\n\n1\ufe0f\u20e3 \u2705 Cita realizada\n2\ufe0f\u20e3 \u274c No pude asistir\n3\ufe0f\u20e3 \ud83d\udd04 Reagendar';
  } else if (['2','reagend','cambiar'].some(k => mensaje.includes(k))) {
    session.estado = 'verificando_disponibilidad'; session.fecha_preferida = 'proximos'; accion = 'verificar_calendar';
    respuesta = '\ud83d\udd0d Buscando pr\u00f3ximos horarios...';
  } else if (['3','menu','volver','principal'].some(k => mensaje.includes(k))) {
    session.estado = 'inicio'; respuesta = MENU;
  } else if (['4','cancel'].some(k => mensaje.includes(k))) {
    session.estado = 'cancelar_confirmacion';
    respuesta = '\u26a0\ufe0f \u00bfEst\u00e1s seguro de *cancelar* tu cita?\n\n\ud83d\udc68\u200d\u2695\ufe0f '+(odont.nombre||'')+'\n\ud83d\udcc5 '+fechaC+(slotC.label ? ' \u2022 '+slotC.label+' hrs' : '')+'\n\n*1* S\u00ed, cancelar\n*2* No, mantener mi cita';
  } else {
    respuesta = '\ud83d\udccb *Tu cita:*\n\n\ud83d\udc68\u200d\u2695\ufe0f '+(odont.nombre||'')+'\n\ud83d\udcc5 '+fechaC+(slotC.label ? ' \u2022 '+slotC.label+' hrs' : '')+'\n\n1\ufe0f\u20e3 Reportar resultado\n2\ufe0f\u20e3 Reagendar\n3\ufe0f\u20e3 Men\u00fa principal\n4\ufe0f\u20e3 \u274c Cancelar cita';
  }

} else if (session.estado === 'cancelar_confirmacion') {
  if (['1','si','s\u00ed','confirmo','cancelar'].some(k => mensaje.includes(k))) {
    if (session.event_id) {
      session.estado = 'cancelando'; accion = 'cancelar_evento'; respuesta = '\u23f3 Cancelando tu cita...';
    } else {
      session.estado = 'completado';
      respuesta = '\u2705 Tu cita ha sido cancelada.\n\nEscribe *hola* para agendar una nueva cita. \ud83e\uddb7';
    }
  } else if (['2','no','mantener'].some(k => mensaje.includes(k))) {
    session.estado = 'gestion_cita';
    respuesta = '\u2705 Mantuvimos tu cita.\n\n1\ufe0f\u20e3 Reportar resultado\n2\ufe0f\u20e3 Reagendar\n3\ufe0f\u20e3 Men\u00fa principal\n4\ufe0f\u20e3 \u274c Cancelar cita';
  } else {
    respuesta = '\u00bfCancelas tu cita?\n\n*1* S\u00ed, cancelar\n*2* No, mantener';
  }

} else if (session.estado === 'realizacion_cita') {
  if (['1','realiz','asisti','si','s\u00ed'].some(k => mensaje.includes(k))) {
    session.estado = 'fin_proceso'; session.resultado_cita = 'realizada';
    respuesta = '\u2705 \u00a1Gracias por tu visita! \ud83d\ude0a\n\n1\ufe0f\u20e3 Agendar nueva cita\n2\ufe0f\u20e3 Cerrar';
  } else if (['2','no','ausente'].some(k => mensaje.includes(k))) {
    session.estado = 'fin_proceso'; session.resultado_cita = 'ausente';
    respuesta = '\ud83d\ude14 Lo sentimos.\n\n1\ufe0f\u20e3 Reagendar cita\n2\ufe0f\u20e3 Cerrar';
  } else if (['3','reagend'].some(k => mensaje.includes(k))) {
    session.estado = 'verificando_disponibilidad'; session.fecha_preferida = 'proximos'; accion = 'verificar_calendar';
    respuesta = '\ud83d\udd0d Buscando pr\u00f3ximos horarios...';
  } else { respuesta = 'Responde *1* si asististe, *2* si no pudiste, o *3* para reagendar.'; }

} else if (session.estado === 'fin_proceso') {
  if (['1','nueva','agendar','reagend','cita'].some(k => mensaje.includes(k))) {
    const nombreG = session.nombre_paciente; const servG = session.servicio;
    session = { estado: 'seleccion_odontologo', nombre_paciente: nombreG, servicio: servG };
    if (servG === 'radiologia') {
      session.odontologo = ODONTOLOGOS['5']; session.estado = 'verificando_disponibilidad'; session.fecha_preferida = 'proximos'; accion = 'verificar_calendar';
      respuesta = '\ud83d\udd0d Buscando horarios con *Dra. Beatriz Bravo*...';
    } else {
      respuesta = '\ud83d\udc4b Hola de nuevo, *'+nombreG+'*! Elige tu especialista:\n\n1\ufe0f\u20e3 Dr. Alejandro Contreras\n2\ufe0f\u20e3 Dra. Mar\u00eda B. Fuenmayor\n3\ufe0f\u20e3 Dr. Germ\u00e1n\n4\ufe0f\u20e3 Dra. Vanessa Touza';
    }
  } else if (['2','cerrar','listo','no'].some(k => mensaje.includes(k))) {
    session.estado = 'completado';
    respuesta = '\u2705 \u00a1Hasta pronto! Fue un placer atenderte en Implantarte. \ud83d\ude0a\n\nEscribe *hola* cuando nos necesites.';
  } else {
    respuesta = session.resultado_cita === 'ausente' ? '1\ufe0f\u20e3 Reagendar cita\n2\ufe0f\u20e3 Cerrar' : '1\ufe0f\u20e3 Agendar nueva cita\n2\ufe0f\u20e3 Cerrar';
  }

} else { session.estado = 'inicio'; respuesta = MENU; }

session.updated_at = new Date().toISOString();
staticData.sessions[telefono] = JSON.parse(JSON.stringify(session));
return [{ json: { telefono, mensaje: msgOriginal, session: JSON.parse(JSON.stringify(session)), respuesta, accion, isTwilio } }];

const input = $input.first().json;
const session = input.session;
const odontologo = session.odontologo;
const fechaPref = session.fecha_preferida || '';

function encontrarProximoDia(doc, desde) {
  const hoy = new Date();
  for (let i = (desde||1); i <= 30; i++) {
    const d = new Date(hoy); d.setDate(d.getDate()+i);
    const raw = d.getDay(); const dia = raw===0?7:raw;
    if (doc.dias.includes(dia)) return { fecha:d, offset:i };
  }
  return null;
}

function parsearFecha(texto) {
  const hoy = new Date(); const t = texto.toLowerCase();
  if (t.includes('hoy')) return new Date(hoy);
  if (t.includes('ma\u00f1ana')||t.includes('manana')) { const m=new Date(hoy);m.setDate(m.getDate()+1);return m; }
  const dias = {lunes:1,martes:2,miercoles:3,jueves:4,viernes:5,sabado:6};
  for (const [n,num] of Object.entries(dias)) { if (t.includes(n)) { const d=new Date(hoy);const diff=(num-d.getDay()+7)%7||7;d.setDate(d.getDate()+diff);return d; } }
  const m1 = texto.match(/(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{4})/);
  if (m1) return new Date(m1[3]+'-'+m1[2].padStart(2,'0')+'-'+m1[1].padStart(2,'0')+'T12:00:00');
  return null;
}

function generarSlots(f, inicio, fin, dur) {
  const slots=[]; const [hI,mI]=inicio.split(':').map(Number); const [hF,mF]=fin.split(':').map(Number);
  let cur=new Date(f); cur.setHours(hI,mI,0,0); const finD=new Date(f); finD.setHours(hF,mF,0,0);
  while (cur<finD) {
    const h=cur.getHours();
    if (h===12) { cur=new Date(cur); cur.setHours(13,0,0,0); continue; }
    const end=new Date(cur.getTime()+dur*60000);
    if (end<=finD) slots.push({inicio:cur.toISOString(),fin:end.toISOString(),label:String(h).padStart(2,'0')+':'+String(cur.getMinutes()).padStart(2,'0')});
    cur=new Date(cur.getTime()+dur*60000);
  }
  return slots;
}

const esProximos = fechaPref==='proximos'||fechaPref==='proximos_mas'||!fechaPref;
const offsetInicio = (fechaPref==='proximos_mas'&&session.ultimo_offset) ? (session.ultimo_offset+1) : 1;
let fecha=null, offsetUsado=null;
if (esProximos) { const r=encontrarProximoDia(odontologo,offsetInicio); if(r){fecha=r.fecha;offsetUsado=r.offset;} }
else { fecha=parsearFecha(fechaPref); }

const staticData=$getWorkflowStaticData('global');
if (!staticData.sessions) staticData.sessions={};
const s=JSON.parse(JSON.stringify(staticData.sessions[input.telefono]||{}));
s.odontologo=odontologo; s.nombre_paciente=session.nombre_paciente; s.servicio=session.servicio;

if (!fecha) {
  s.estado='inicio'; staticData.sessions[input.telefono]=s;
  return [{ json: Object.assign({},input,{respuesta:'\ud83d\ude14 No encontramos horarios en los pr\u00f3ximos 30 d\u00edas. Escribe *hola* para volver al men\u00fa.',session:JSON.parse(JSON.stringify(s)),_error:'no_fecha'}) }];
}

const rawDay=fecha.getDay(); const diaSemana=rawDay===0?7:rawDay;
const trabaja=odontologo.dias.includes(diaSemana); const esSab=diaSemana===6;
const horaFin=(esSab&&odontologo.fin_sabado)?odontologo.fin_sabado:odontologo.fin;

if (!trabaja) {
  const dn=['Dom','Lun','Mar','Mi\u00e9','Jue','Vie','S\u00e1b'];
  s.estado='fecha_hora'; staticData.sessions[input.telefono]=s;
  return [{ json: Object.assign({},input,{respuesta:'\ud83d\ude14 '+odontologo.nombre+' no atiende los '+dn[rawDay]+'.\n\n\ud83d\udcc5 \u00bfQu\u00e9 otro d\u00eda?\n\nEscribe el d\u00eda o una fecha (ej. *05/05/2026*).',session:JSON.parse(JSON.stringify(s)),_error:'no_trabaja'}) }];
}

const todosSlots=generarSlots(fecha,odontologo.inicio,horaFin,odontologo.duracion_min);
const fechaStr=fecha.toLocaleDateString('es-VE',{weekday:'long',day:'numeric',month:'long',year:'numeric'});
const tMin=new Date(fecha); tMin.setHours(0,0,0,0);
const tMax=new Date(fecha); tMax.setHours(23,59,59,999);
const freebusy_params={timeMin:tMin.toISOString(),timeMax:tMax.toISOString(),items:[{id:odontologo.calendar_id}]};

s.estado='verificando_disponibilidad'; s.todos_slots=todosSlots; s.fecha_str=fechaStr; s.esProximos=esProximos;
if (offsetUsado!==null) s.ultimo_offset=offsetUsado;
staticData.sessions[input.telefono]=s;
return [{ json: Object.assign({},input,{session:JSON.parse(JSON.stringify(s)),todos_slots:todosSlots,fecha_str:fechaStr,freebusy_params,esProximos,ultimo_offset:offsetUsado,_error:null}) }];

const verificarData = $('Verificar Disponibilidad').first().json;
const freebusyResp = $input.first().json;
const telefono = verificarData.telefono;
const session = verificarData.session;
const odontologo = session.odontologo || {};
const todosSlots = verificarData.todos_slots || [];
const fechaStr = verificarData.fecha_str || '';
const esProximos = verificarData.esProximos;
const ultimoOffset = verificarData.ultimo_offset;

let ocupados = [];
try {
  const calId = odontologo.calendar_id;
  if (freebusyResp.calendars && freebusyResp.calendars[calId]) {
    ocupados = freebusyResp.calendars[calId].busy || [];
  }
} catch(e) { ocupados = []; }

const libres = todosSlots.filter(sl => {
  const sS=new Date(sl.inicio).getTime(); const sE=new Date(sl.fin).getTime();
  return !ocupados.some(b => sS < new Date(b.end).getTime() && sE > new Date(b.start).getTime());
});
const primeros = libres.slice(0,3);

const staticData=$getWorkflowStaticData('global');
if (!staticData.sessions) staticData.sessions={};
const s=JSON.parse(JSON.stringify(staticData.sessions[telefono]||{}));
s.odontologo=odontologo; s.nombre_paciente=session.nombre_paciente; s.servicio=session.servicio;

let respuesta='';
if (primeros.length>0) {
  s.estado='seleccion_slot'; s.slots_propuestos=primeros;
  respuesta='\ud83d\udcc5 *Horarios disponibles con '+odontologo.nombre+'*\n'+fechaStr+':\n\n'+primeros.map((sl,i)=>(i+1)+'\ufe0f\u20e3 '+sl.label+' hrs').join('\n')+'\n\n\u00bfCu\u00e1l prefieres? Responde *1*, *2* o *3*.';
} else {
  s.estado='fecha_hora';
  respuesta='\ud83d\ude14 Todos los horarios de ese d\u00eda est\u00e1n ocupados.\n\n\ud83d\udcc5 \u00bfQu\u00e9 otro d\u00eda prefieres?\n\nEscribe el d\u00eda (ej. *lunes*) o una fecha (ej. *05/05/2026*).';
}

staticData.sessions[telefono]=s;
return [{ json: { telefono, session: JSON.parse(JSON.stringify(s)), respuesta } }];

const input = $input.first().json;
const session = input.session;
const odontologo = session.odontologo;
const slot = session.slot_confirmado;
if (!slot||!odontologo) return [{ json:{...input,respuesta:'\u274c Error al crear la cita. Escribe *hola* para reiniciar.'} }];
const staticData=$getWorkflowStaticData('global');
